// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Contrato) predicate.Contrato {
	return predicate.Contrato(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Contrato) predicate.Contrato {
	return predicate.Contrato(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Contrato) predicate.Contrato {
	return predicate.Contrato(sql.NotPredicates(p))
}
